/**
 * DOM 节点池 - 复用节点减少 GC
 * 
 * 管理 DOM 节点的复用和回收，减少创建和销毁开销。
 * 支持按类型分组管理节点。
 * 
 * @module node-pool
 */

/**
 * DOM 节点池类
 * 
 * 实现节点的获取、归还和清理，支持按类型分组管理。
 */
class DOMNodePool {
  /**
   * @param {Object} options - 配置选项
   * @param {number} [options.maxSize=100] - 每种类型节点池的最大容量
   * @param {Function} [options.onAcquire] - 节点获取时的回调
   * @param {Function} [options.onRelease] - 节点归还时的回调
   */
  constructor(options = {}) {
    this.maxSize = options.maxSize || 100;
    this.onAcquire = options.onAcquire || null;
    this.onRelease = options.onRelease || null;
    
    /** @type {Map<string, HTMLElement[]>} 按类型分组的节点池 */
    this.pools = new Map();
    
    /** @type {Map<HTMLElement, string>} 节点到类型的映射，用于追踪 */
    this._nodeTypeMap = new WeakMap();
    
    /** @type {Object} 统计信息 */
    this.stats = {
      acquired: 0,
      released: 0,
      created: 0,
      reused: 0
    };
  }

  /**
   * 获取一个节点（从池中取或新建）
   * 
   * @param {string} type - 节点类型标识
   * @param {Function} createFn - 创建函数，当池中无可用节点时调用
   * @returns {HTMLElement} DOM 节点
   */
  acquire(type, createFn) {
    let node;
    const pool = this.pools.get(type);
    
    if (pool && pool.length > 0) {
      // 从池中取出节点
      node = pool.pop();
      this.stats.reused++;
    } else {
      // 创建新节点
      node = createFn();
      this.stats.created++;
    }
    
    this._nodeTypeMap.set(node, type);
    this.stats.acquired++;
    
    if (this.onAcquire) {
      this.onAcquire(node, type);
    }
    
    return node;
  }

  /**
   * 归还节点到池中
   * 
   * @param {string} type - 节点类型标识
   * @param {HTMLElement} node - 要归还的节点
   * @returns {boolean} 是否成功归还（池未满时返回 true）
   */
  release(type, node) {
    if (!node) {
      return false;
    }
    
    // 获取或创建该类型的池
    let pool = this.pools.get(type);
    if (!pool) {
      pool = [];
      this.pools.set(type, pool);
    }
    
    // 检查池是否已满
    if (pool.length >= this.maxSize) {
      // 池已满，不再接收，让节点被 GC
      return false;
    }
    
    // 清理节点状态
    this._resetNode(node);
    
    // 归还到池中
    pool.push(node);
    this._nodeTypeMap.set(node, type);
    this.stats.released++;
    
    if (this.onRelease) {
      this.onRelease(node, type);
    }
    
    return true;
  }

  /**
   * 清空指定类型的池
   * 
   * @param {string} type - 节点类型标识
   */
  clearType(type) {
    const pool = this.pools.get(type);
    if (pool) {
      pool.length = 0;
    }
  }

  /**
   * 清空所有池
   */
  clear() {
    for (const pool of this.pools.values()) {
      pool.length = 0;
    }
    this.pools.clear();
  }

  /**
   * 获取指定类型池的当前大小
   * 
   * @param {string} type - 节点类型标识
   * @returns {number} 池中节点数量
   */
  getPoolSize(type) {
    const pool = this.pools.get(type);
    return pool ? pool.length : 0;
  }

  /**
   * 获取所有池的总节点数
   * 
   * @returns {number} 总节点数
   */
  getTotalSize() {
    let total = 0;
    for (const pool of this.pools.values()) {
      total += pool.length;
    }
    return total;
  }

  /**
   * 获取统计信息
   * 
   * @returns {Object} 统计数据
   */
  getStats() {
    return {
      ...this.stats,
      poolCount: this.pools.size,
      totalPooled: this.getTotalSize(),
      reuseRate: this.stats.acquired > 0 
        ? (this.stats.reused / this.stats.acquired * 100).toFixed(2) + '%'
        : '0%'
    };
  }

  /**
   * 重置节点状态
   * @private
   * @param {HTMLElement} node - 要重置的节点
   */
  _resetNode(node) {
    // 从 DOM 中移除
    if (node.parentNode) {
      node.parentNode.removeChild(node);
    }
    
    // 清空内容
    node.textContent = '';
    
    // 移除所有事件监听器（通过克隆替换）
    // 注意：这里不做克隆，因为会破坏节点引用
    // 调用方应负责移除事件监听器
    
    // 重置常见属性
    node.className = '';
    node.removeAttribute('style');
    node.removeAttribute('data-id');
    node.removeAttribute('data-index');
  }
}

// 导出
export { DOMNodePool };
