/**
 * 搜索控制器 - 管理搜索生命周期
 * 
 * 实现防抖搜索、任务取消、渐进加载功能。
 * 
 * @module search-controller
 */

/**
 * @typedef {Object} SearchState
 * @property {string} term - 搜索词
 * @property {Object} filters - 过滤条件
 * @property {Array} results - 搜索结果
 * @property {number} totalCount - 总匹配数
 * @property {number} loadedCount - 已加载数
 * @property {boolean} isSearching - 是否正在搜索
 * @property {boolean} hasMore - 是否有更多结果
 */

/**
 * @typedef {Object} SearchTask
 * @property {string} id - 任务 ID
 * @property {string} term - 搜索词
 * @property {Object} filters - 过滤条件
 * @property {string} status - 状态: 'pending' | 'running' | 'completed' | 'cancelled'
 * @property {Function} resolve - Promise resolve
 * @property {Function} reject - Promise reject
 * @property {AbortController} [abortController] - 用于取消的控制器
 */

/**
 * 搜索控制器类
 * 
 * 管理搜索的防抖、取消和渐进加载。
 */
class SearchController {
  /**
   * @param {Object} options - 配置选项
   * @param {number} [options.debounceMs=200] - 防抖延迟 (ms)
   * @param {number} [options.batchSize=20] - 每批加载数量
   * @param {Function} [options.searchFn] - 搜索函数，接收 (term, filters) 返回结果数组
   * @param {Function} [options.onSearchStart] - 搜索开始回调
   * @param {Function} [options.onSearchComplete] - 搜索完成回调
   * @param {Function} [options.onSearchCancel] - 搜索取消回调
   */
  constructor(options = {}) {
    this.debounceMs = options.debounceMs ?? 200;
    this.batchSize = options.batchSize ?? 20;
    this.searchFn = options.searchFn ?? null;
    this.onSearchStart = options.onSearchStart ?? null;
    this.onSearchComplete = options.onSearchComplete ?? null;
    this.onSearchCancel = options.onSearchCancel ?? null;

    /** @type {SearchTask|null} */
    this.currentTask = null;
    /** @type {number|null} */
    this.debounceTimer = null;
    /** @type {SearchState} */
    this.state = this._createInitialState();
    /** @type {Array} */
    this._allResults = [];
    /** @type {number} */
    this._taskIdCounter = 0;
  }

  /**
   * 创建初始状态
   * @private
   * @returns {SearchState}
   */
  _createInitialState() {
    return {
      term: '',
      filters: {},
      results: [],
      totalCount: 0,
      loadedCount: 0,
      isSearching: false,
      hasMore: false,
    };
  }

  /**
   * 生成唯一任务 ID
   * @private
   * @returns {string}
   */
  _generateTaskId() {
    return `search-${++this._taskIdCounter}-${Date.now()}`;
  }

  /**
   * 执行搜索（带防抖）
   * 
   * @param {string} term - 搜索词
   * @param {Object} [filters={}] - 过滤条件
   * @returns {Promise<SearchState>} 搜索结果状态
   */
  search(term, filters = {}) {
    // 取消之前的防抖定时器
    if (this.debounceTimer !== null) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }

    // 取消之前未完成的搜索任务（包括 pending 和 running 状态）
    if (this.currentTask && 
        (this.currentTask.status === 'running' || this.currentTask.status === 'pending')) {
      this._cancelTask(this.currentTask);
    }

    // 如果搜索词为空，立即返回空结果
    if (!term || (typeof term === 'string' && term.trim() === '')) {
      this._resetState();
      return Promise.resolve(this.state);
    }

    return new Promise((resolve, reject) => {
      const taskId = this._generateTaskId();
      
      /** @type {SearchTask} */
      const task = {
        id: taskId,
        term: typeof term === 'string' ? term.trim() : String(term),
        filters: { ...filters },
        status: 'pending',
        resolve,
        reject,
      };

      this.currentTask = task;
      this.state.isSearching = true;

      // 应用防抖延迟
      this.debounceTimer = setTimeout(() => {
        this.debounceTimer = null;
        this._executeSearch(task);
      }, this.debounceMs);
    });
  }

  /**
   * 立即执行搜索（无防抖）
   * 
   * @param {string} term - 搜索词
   * @param {Object} [filters={}] - 过滤条件
   * @returns {Promise<SearchState>} 搜索结果状态
   */
  searchImmediate(term, filters = {}) {
    // 取消之前的防抖定时器
    if (this.debounceTimer !== null) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }

    // 取消之前未完成的搜索任务（包括 pending 和 running 状态）
    if (this.currentTask && 
        (this.currentTask.status === 'running' || this.currentTask.status === 'pending')) {
      this._cancelTask(this.currentTask);
    }

    // 如果搜索词为空，立即返回空结果
    if (!term || (typeof term === 'string' && term.trim() === '')) {
      this._resetState();
      return Promise.resolve(this.state);
    }

    return new Promise((resolve, reject) => {
      const taskId = this._generateTaskId();
      
      /** @type {SearchTask} */
      const task = {
        id: taskId,
        term: typeof term === 'string' ? term.trim() : String(term),
        filters: { ...filters },
        status: 'pending',
        resolve,
        reject,
      };

      this.currentTask = task;
      this.state.isSearching = true;

      // 立即执行
      this._executeSearch(task);
    });
  }

  /**
   * 执行搜索任务
   * @private
   * @param {SearchTask} task - 搜索任务
   */
  _executeSearch(task) {
    // 检查任务是否已被取消
    if (task.status === 'cancelled') {
      return;
    }

    task.status = 'running';

    // 触发搜索开始回调
    if (typeof this.onSearchStart === 'function') {
      try {
        this.onSearchStart(task.term, task.filters);
      } catch (e) {
        console.warn('[SearchController] onSearchStart callback error:', e);
      }
    }

    try {
      // 执行搜索
      let results = [];
      if (typeof this.searchFn === 'function') {
        results = this.searchFn(task.term, task.filters);
        // 处理 Promise 返回值
        if (results && typeof results.then === 'function') {
          results.then(asyncResults => {
            if (task.status === 'cancelled') return;
            this._handleSearchResults(task, asyncResults || []);
          }).catch(error => {
            if (task.status === 'cancelled') return;
            this._handleSearchError(task, error);
          });
          return;
        }
      }

      // 同步结果处理
      if (task.status === 'cancelled') return;
      this._handleSearchResults(task, results || []);

    } catch (error) {
      if (task.status === 'cancelled') return;
      this._handleSearchError(task, error);
    }
  }

  /**
   * 处理搜索结果
   * @private
   * @param {SearchTask} task - 搜索任务
   * @param {Array} results - 搜索结果
   */
  _handleSearchResults(task, results) {
    if (task.status === 'cancelled') return;

    task.status = 'completed';
    
    // 保存所有结果
    this._allResults = Array.isArray(results) ? results : [];
    const totalCount = this._allResults.length;

    // 渐进加载：如果结果超过 100 条，先返回前 batchSize 条
    const shouldProgressiveLoad = totalCount > 100;
    const firstBatchSize = shouldProgressiveLoad ? this.batchSize : totalCount;
    const firstBatch = this._allResults.slice(0, firstBatchSize);

    // 更新状态
    this.state = {
      term: task.term,
      filters: task.filters,
      results: firstBatch,
      totalCount,
      loadedCount: firstBatch.length,
      isSearching: false,
      hasMore: firstBatch.length < totalCount,
    };

    // 触发搜索完成回调
    if (typeof this.onSearchComplete === 'function') {
      try {
        this.onSearchComplete(this.state);
      } catch (e) {
        console.warn('[SearchController] onSearchComplete callback error:', e);
      }
    }

    // 解析 Promise
    task.resolve(this.state);
  }

  /**
   * 处理搜索错误
   * @private
   * @param {SearchTask} task - 搜索任务
   * @param {Error} error - 错误对象
   */
  _handleSearchError(task, error) {
    task.status = 'completed';
    this.state.isSearching = false;
    
    console.error('[SearchController] Search error:', error);
    task.reject(error);
  }

  /**
   * 取消当前搜索
   * 
   * @returns {boolean} 是否成功取消
   */
  cancel() {
    // 取消防抖定时器
    if (this.debounceTimer !== null) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }

    // 取消当前任务
    if (this.currentTask) {
      return this._cancelTask(this.currentTask);
    }

    return false;
  }

  /**
   * 取消指定任务
   * @private
   * @param {SearchTask} task - 要取消的任务
   * @returns {boolean} 是否成功取消
   */
  _cancelTask(task) {
    if (!task || task.status === 'completed' || task.status === 'cancelled') {
      return false;
    }

    const wasRunning = task.status === 'running';
    task.status = 'cancelled';

    // 更新状态
    this.state.isSearching = false;

    // 触发取消回调
    if (wasRunning && typeof this.onSearchCancel === 'function') {
      try {
        this.onSearchCancel(task.term);
      } catch (e) {
        console.warn('[SearchController] onSearchCancel callback error:', e);
      }
    }

    // 静默取消，不调用 reject
    return true;
  }

  /**
   * 重置状态
   * @private
   */
  _resetState() {
    this._allResults = [];
    this.state = this._createInitialState();
    this.currentTask = null;
  }

  /**
   * 渐进加载更多结果
   * 
   * @returns {Promise<SearchState>} 更新后的状态
   */
  loadMore() {
    return new Promise((resolve) => {
      if (!this.state.hasMore || this._allResults.length === 0) {
        resolve(this.state);
        return;
      }

      const currentLoaded = this.state.loadedCount;
      const nextBatchEnd = Math.min(currentLoaded + this.batchSize, this._allResults.length);
      const nextBatch = this._allResults.slice(currentLoaded, nextBatchEnd);

      // 追加到现有结果
      this.state = {
        ...this.state,
        results: [...this.state.results, ...nextBatch],
        loadedCount: nextBatchEnd,
        hasMore: nextBatchEnd < this._allResults.length,
      };

      resolve(this.state);
    });
  }

  /**
   * 获取当前搜索状态
   * 
   * @returns {SearchState}
   */
  getState() {
    return { ...this.state };
  }

  /**
   * 检查是否正在搜索
   * 
   * @returns {boolean}
   */
  isSearching() {
    return this.state.isSearching;
  }

  /**
   * 检查是否有更多结果可加载
   * 
   * @returns {boolean}
   */
  hasMoreResults() {
    return this.state.hasMore;
  }

  /**
   * 获取当前任务
   * 
   * @returns {SearchTask|null}
   */
  getCurrentTask() {
    return this.currentTask;
  }

  /**
   * 销毁控制器，清理资源
   */
  destroy() {
    this.cancel();
    this._resetState();
    this.searchFn = null;
    this.onSearchStart = null;
    this.onSearchComplete = null;
    this.onSearchCancel = null;
  }
}

// 导出
export { SearchController };
