/**
 * 批量更新器 - 实现状态更新合并
 * 
 * 在指定时间窗口内合并多次状态更新，减少 UI 刷新次数。
 * 
 * @module batch-updater
 */

/**
 * @typedef {Object} BatchUpdaterOptions
 * @property {number} [windowMs=100] - 合并时间窗口 (ms)
 * @property {Function} [onFlush] - 刷新回调，接收合并后的更新
 * @property {Function} [mergeFn] - 自定义合并函数，接收 (accumulated, newUpdate) 返回合并结果
 */

/**
 * @typedef {Object} BatchUpdaterState
 * @property {boolean} isPending - 是否有待处理的更新
 * @property {number} pendingCount - 待处理更新数量
 * @property {number} lastFlushTime - 上次刷新时间戳
 */

/**
 * 批量更新器类
 * 
 * 实现 100ms 时间窗口内的状态合并，减少 UI 刷新频率。
 * Requirements: 4.1, 4.3
 */
class BatchUpdater {
  /**
   * @param {BatchUpdaterOptions} options - 配置选项
   */
  constructor(options = {}) {
    /** @type {number} 合并时间窗口 (ms) */
    this.windowMs = options.windowMs ?? 100;
    /** @type {Function|null} 刷新回调 */
    this.onFlush = options.onFlush ?? null;
    /** @type {Function|null} 自定义合并函数 */
    this.mergeFn = options.mergeFn ?? null;

    /** @type {any} 累积的更新 */
    this._accumulated = null;
    /** @type {number|null} 定时器 ID */
    this._timer = null;
    /** @type {number} 待处理更新数量 */
    this._pendingCount = 0;
    /** @type {number} 上次刷新时间戳 */
    this._lastFlushTime = 0;
    /** @type {number} 窗口开始时间 */
    this._windowStartTime = 0;
  }

  /**
   * 提交一个更新
   * 
   * 更新会被累积，在时间窗口结束后统一刷新。
   * 
   * @param {any} update - 要提交的更新
   * @returns {boolean} 是否成功提交
   */
  schedule(update) {
    if (update === undefined) {
      return false;
    }

    const now = Date.now();

    // 如果是窗口内的第一个更新，记录窗口开始时间
    if (this._timer === null) {
      this._windowStartTime = now;
    }

    // 合并更新
    if (this._accumulated === null) {
      this._accumulated = this._cloneUpdate(update);
    } else if (typeof this.mergeFn === 'function') {
      this._accumulated = this.mergeFn(this._accumulated, update);
    } else {
      // 默认合并策略：对象浅合并，其他类型直接覆盖
      this._accumulated = this._defaultMerge(this._accumulated, update);
    }

    this._pendingCount++;

    // 如果没有定时器，启动一个
    if (this._timer === null) {
      this._timer = setTimeout(() => {
        this._flush();
      }, this.windowMs);
    }

    return true;
  }

  /**
   * 立即刷新所有待处理的更新
   * 
   * @returns {any} 刷新的更新内容
   */
  flush() {
    return this._flush();
  }

  /**
   * 取消所有待处理的更新
   * 
   * @returns {boolean} 是否有更新被取消
   */
  cancel() {
    const hadPending = this._timer !== null;

    if (this._timer !== null) {
      clearTimeout(this._timer);
      this._timer = null;
    }

    this._accumulated = null;
    this._pendingCount = 0;
    this._windowStartTime = 0;

    return hadPending;
  }

  /**
   * 获取当前状态
   * 
   * @returns {BatchUpdaterState}
   */
  getState() {
    return {
      isPending: this._timer !== null,
      pendingCount: this._pendingCount,
      lastFlushTime: this._lastFlushTime,
    };
  }

  /**
   * 检查是否有待处理的更新
   * 
   * @returns {boolean}
   */
  isPending() {
    return this._timer !== null;
  }

  /**
   * 获取待处理更新数量
   * 
   * @returns {number}
   */
  getPendingCount() {
    return this._pendingCount;
  }

  /**
   * 销毁更新器，清理资源
   */
  destroy() {
    this.cancel();
    this.onFlush = null;
    this.mergeFn = null;
  }

  /**
   * 执行刷新
   * @private
   * @returns {any} 刷新的更新内容
   */
  _flush() {
    if (this._timer !== null) {
      clearTimeout(this._timer);
      this._timer = null;
    }

    const updates = this._accumulated;
    const count = this._pendingCount;

    this._accumulated = null;
    this._pendingCount = 0;
    this._lastFlushTime = Date.now();
    this._windowStartTime = 0;

    // 触发回调
    if (updates !== null && typeof this.onFlush === 'function') {
      try {
        this.onFlush(updates, count);
      } catch (error) {
        console.warn('[BatchUpdater] onFlush callback error:', error);
      }
    }

    return updates;
  }

  /**
   * 默认合并策略
   * @private
   * @param {any} accumulated - 累积的更新
   * @param {any} newUpdate - 新的更新
   * @returns {any} 合并结果
   */
  _defaultMerge(accumulated, newUpdate) {
    // 如果两者都是普通对象，进行浅合并
    if (this._isPlainObject(accumulated) && this._isPlainObject(newUpdate)) {
      return { ...accumulated, ...newUpdate };
    }

    // 如果两者都是数组，合并数组
    if (Array.isArray(accumulated) && Array.isArray(newUpdate)) {
      return [...accumulated, ...newUpdate];
    }

    // 如果两者都是 Set，合并 Set
    if (accumulated instanceof Set && newUpdate instanceof Set) {
      const merged = new Set(accumulated);
      for (const item of newUpdate) {
        merged.add(item);
      }
      return merged;
    }

    // 如果两者都是 Map，合并 Map
    if (accumulated instanceof Map && newUpdate instanceof Map) {
      const merged = new Map(accumulated);
      for (const [key, value] of newUpdate) {
        merged.set(key, value);
      }
      return merged;
    }

    // 其他情况直接覆盖
    return newUpdate;
  }

  /**
   * 克隆更新（浅克隆）
   * @private
   * @param {any} update - 要克隆的更新
   * @returns {any} 克隆结果
   */
  _cloneUpdate(update) {
    if (this._isPlainObject(update)) {
      return { ...update };
    }
    if (Array.isArray(update)) {
      return [...update];
    }
    if (update instanceof Set) {
      return new Set(update);
    }
    if (update instanceof Map) {
      return new Map(update);
    }
    return update;
  }

  /**
   * 检查是否为普通对象
   * @private
   * @param {any} value - 要检查的值
   * @returns {boolean}
   */
  _isPlainObject(value) {
    if (value === null || typeof value !== 'object') {
      return false;
    }
    const proto = Object.getPrototypeOf(value);
    return proto === null || proto === Object.prototype;
  }
}

// 导出
export { BatchUpdater };
