/**
 * 虚拟列表管理器 - 实现虚拟滚动
 * 
 * 仅渲染可视区域内的列表项，减少 DOM 节点数量。
 * 集成 DOMNodePool 进行节点复用。
 * 支持移动端内存优化：主动释放不可见区域的 DOM 节点。
 * 
 * @module virtual-list
 */

import { DOMNodePool } from './node-pool.js';

/**
 * @typedef {Object} VirtualListState
 * @property {Array} items - 所有数据项
 * @property {number} totalHeight - 列表总高度
 * @property {number} scrollTop - 当前滚动位置
 * @property {Object} visibleRange - 可见范围 { start, end }
 * @property {Map} renderedNodes - 已渲染的节点映射
 * @property {number} itemHeight - 单项高度
 */

/** 移动端视口宽度阈值 (px) */
const MOBILE_VIEWPORT_THRESHOLD = 640;

/** 移动端内存释放延迟 (ms) */
const MOBILE_MEMORY_RELEASE_DELAY = 500;

/**
 * 虚拟列表管理器类
 * 
 * 实现虚拟滚动，只渲染可见区域的内容加上缓冲区。
 * 移动端支持主动释放不可见区域的 DOM 节点以优化内存。
 */
class VirtualListManager {
  /**
   * @param {Object} options - 配置选项
   * @param {HTMLElement} [options.container] - 滚动容器元素
   * @param {number} [options.itemHeight=60] - 单项高度 (px)
   * @param {number} [options.bufferSize=5] - 上下缓冲区大小
   * @param {number} [options.viewportHeight=400] - 视口高度 (px)
   * @param {Function} [options.renderItem] - 渲染单个项目的函数
   * @param {DOMNodePool} [options.nodePool] - 外部节点池实例
   * @param {boolean} [options.aggressiveMemoryRelease=false] - 是否启用激进内存释放（移动端）
   */
  constructor(options = {}) {
    this.container = options.container || null;
    this.itemHeight = options.itemHeight || 60;
    this.bufferSize = options.bufferSize || 5;
    this.viewportHeight = options.viewportHeight || 400;
    this.renderItem = options.renderItem || null;
    
    // 使用外部节点池或创建新的
    this.nodePool = options.nodePool || new DOMNodePool({ maxSize: 100 });
    this._ownsNodePool = !options.nodePool;
    
    /** @type {Array} 所有数据项 */
    this.items = [];
    
    /** @type {number} 当前滚动位置 */
    this.scrollTop = 0;
    
    /** @type {Object} 可见范围 { start, end } */
    this.visibleRange = { start: 0, end: 0 };
    
    /** @type {Map<number, HTMLElement>} 已渲染的节点映射 (index -> node) */
    this.renderedNodes = new Map();
    
    /** @type {string} 节点池类型标识 */
    this._nodeType = 'virtual-list-item';
    
    /** @type {boolean} 是否启用激进内存释放 */
    this.aggressiveMemoryRelease = options.aggressiveMemoryRelease || false;
    
    /** @type {number|null} 内存释放定时器 */
    this._memoryReleaseTimer = null;
    
    /** @type {Object} 上一次的可见范围，用于检测大幅滚动 */
    this._lastVisibleRange = { start: 0, end: 0 };
  }

  /**
   * 设置数据源
   * 
   * @param {Array} items - 列表项数据
   */
  setItems(items) {
    this.items = Array.isArray(items) ? items : [];
    // 重置渲染状态
    this._recycleAllNodes();
    this.visibleRange = { start: 0, end: 0 };
  }

  /**
   * 获取列表总高度
   * 
   * @returns {number} 总高度 (px)
   */
  getTotalHeight() {
    return this.items.length * this.itemHeight;
  }

  /**
   * 更新可见区域
   * 
   * @param {number} scrollTop - 滚动位置
   */
  updateVisibleRange(scrollTop) {
    this.scrollTop = Math.max(0, scrollTop);
    
    const totalItems = this.items.length;
    if (totalItems === 0) {
      this.visibleRange = { start: 0, end: 0 };
      return;
    }
    
    // 计算可见区域的起始和结束索引
    const visibleStart = Math.floor(this.scrollTop / this.itemHeight);
    const visibleCount = Math.ceil(this.viewportHeight / this.itemHeight);
    const visibleEnd = Math.min(visibleStart + visibleCount, totalItems);
    
    // 添加缓冲区
    const start = Math.max(0, visibleStart - this.bufferSize);
    const end = Math.min(totalItems, visibleEnd + this.bufferSize);
    
    this.visibleRange = { start, end };
  }

  /**
   * 获取当前渲染的节点数量
   * 
   * @returns {number} 渲染的节点数
   */
  getRenderedCount() {
    return this.renderedNodes.size;
  }

  /**
   * 获取应该渲染的项目数量（基于可见范围）
   * 
   * @returns {number} 应渲染的项目数
   */
  getExpectedRenderCount() {
    return this.visibleRange.end - this.visibleRange.start;
  }

  /**
   * 渲染可见项
   * 
   * @returns {DocumentFragment|null} 渲染结果，如果没有变化返回 null
   */
  render() {
    const { start, end } = this.visibleRange;
    
    // 回收不在可见范围内的节点
    this._recycleOutOfRangeNodes(start, end);
    
    // 创建 DocumentFragment 用于批量插入
    const fragment = document.createDocumentFragment();
    let hasNewNodes = false;
    
    // 渲染可见范围内的项目
    for (let i = start; i < end; i++) {
      if (!this.renderedNodes.has(i)) {
        const node = this._renderItemAtIndex(i);
        if (node) {
          fragment.appendChild(node);
          this.renderedNodes.set(i, node);
          hasNewNodes = true;
        }
      }
    }
    
    return hasNewNodes ? fragment : null;
  }

  /**
   * 获取所有已渲染的节点（按索引排序）
   * 
   * @returns {HTMLElement[]} 已渲染的节点数组
   */
  getRenderedNodes() {
    const entries = Array.from(this.renderedNodes.entries());
    entries.sort((a, b) => a[0] - b[0]);
    return entries.map(([, node]) => node);
  }

  /**
   * 销毁并清理资源
   */
  destroy() {
    // 清理内存释放定时器
    this._cancelMemoryReleaseTimer();
    
    this._recycleAllNodes();
    
    // 如果是自己创建的节点池，清理它
    if (this._ownsNodePool) {
      this.nodePool.clear();
    }
    
    this.items = [];
    this.container = null;
    this.renderItem = null;
  }

  /**
   * 启用激进内存释放模式（移动端优化）
   * 
   * 当启用时，会在滚动停止后主动释放不可见区域的 DOM 节点
   */
  enableAggressiveMemoryRelease() {
    this.aggressiveMemoryRelease = true;
  }

  /**
   * 禁用激进内存释放模式
   */
  disableAggressiveMemoryRelease() {
    this.aggressiveMemoryRelease = false;
    this._cancelMemoryReleaseTimer();
  }

  /**
   * 触发延迟内存释放
   * 
   * 在滚动停止后延迟释放不可见区域的节点，
   * 避免频繁滚动时的性能问题
   */
  scheduleMemoryRelease() {
    if (!this.aggressiveMemoryRelease) return;
    
    this._cancelMemoryReleaseTimer();
    
    this._memoryReleaseTimer = setTimeout(() => {
      this._releaseDistantNodes();
      this._memoryReleaseTimer = null;
    }, MOBILE_MEMORY_RELEASE_DELAY);
  }

  /**
   * 取消内存释放定时器
   * @private
   */
  _cancelMemoryReleaseTimer() {
    if (this._memoryReleaseTimer) {
      clearTimeout(this._memoryReleaseTimer);
      this._memoryReleaseTimer = null;
    }
  }

  /**
   * 释放距离可见区域较远的节点
   * 
   * 只保留可见区域和紧邻的缓冲区节点，
   * 释放更远的节点以节省内存
   * @private
   */
  _releaseDistantNodes() {
    const { start, end } = this.visibleRange;
    
    // 计算紧邻缓冲区（比正常缓冲区更小）
    const tightBuffer = Math.max(1, Math.floor(this.bufferSize / 2));
    const keepStart = Math.max(0, start - tightBuffer);
    const keepEnd = Math.min(this.items.length, end + tightBuffer);
    
    let releasedCount = 0;
    
    for (const [index, node] of this.renderedNodes.entries()) {
      if (index < keepStart || index >= keepEnd) {
        this.nodePool.release(this._nodeType, node);
        this.renderedNodes.delete(index);
        releasedCount++;
      }
    }
    
    return releasedCount;
  }

  /**
   * 获取内存使用统计
   * 
   * @returns {Object} 内存统计信息
   */
  getMemoryStats() {
    return {
      renderedNodes: this.renderedNodes.size,
      pooledNodes: this.nodePool.getTotalSize(),
      totalItems: this.items.length,
      visibleRange: { ...this.visibleRange },
      aggressiveMemoryRelease: this.aggressiveMemoryRelease
    };
  }

  /**
   * 渲染指定索引的项目
   * @private
   * @param {number} index - 项目索引
   * @returns {HTMLElement|null} 渲染的节点
   */
  _renderItemAtIndex(index) {
    const item = this.items[index];
    if (!item) return null;
    
    // 从节点池获取或创建节点
    const node = this.nodePool.acquire(this._nodeType, () => {
      return this._createDefaultNode();
    });
    
    // 设置位置（使用 transform 避免重排）
    const top = index * this.itemHeight;
    node.style.position = 'absolute';
    node.style.top = '0';
    node.style.left = '0';
    node.style.right = '0';
    node.style.transform = `translateY(${top}px)`;
    node.style.height = `${this.itemHeight}px`;
    node.setAttribute('data-index', index);
    
    // 使用自定义渲染函数或默认渲染
    if (this.renderItem) {
      this.renderItem(node, item, index);
    } else {
      node.textContent = String(item);
    }
    
    return node;
  }

  /**
   * 创建默认节点
   * @private
   * @returns {HTMLElement}
   */
  _createDefaultNode() {
    const node = document.createElement('div');
    node.className = 'rlh-virtual-list-item';
    return node;
  }

  /**
   * 回收不在可见范围内的节点
   * @private
   * @param {number} start - 可见范围起始
   * @param {number} end - 可见范围结束
   */
  _recycleOutOfRangeNodes(start, end) {
    for (const [index, node] of this.renderedNodes.entries()) {
      if (index < start || index >= end) {
        this.nodePool.release(this._nodeType, node);
        this.renderedNodes.delete(index);
      }
    }
  }

  /**
   * 回收所有已渲染的节点
   * @private
   */
  _recycleAllNodes() {
    for (const [, node] of this.renderedNodes.entries()) {
      this.nodePool.release(this._nodeType, node);
    }
    this.renderedNodes.clear();
  }
}

// 导出
export { VirtualListManager };
